212	// adjustInstallTargets returns a shallow copy of pkg with Root.Target overridden
213	// to "plugins/<name>" (relative to installRoot) and Skills targets remapped to
214	// the provided absolute agentSkillsDir/claudeSkillsDir paths.
215	func adjustInstallTargets(pkg *registry.Package, name, agentSkillsDir, claudeSkillsDir string) *registry.Package {
216		adjusted := *pkg
217		adjustedInstall := pkg.Install
218	
219		src := "."
220		if pkg.Install.Root != nil {
221			src = pkg.Install.Root.Source
222		}
223		adjustedInstall.Root = &registry.InstallMapping{
224			Source: src,
225			Target: filepath.Join("plugins", name),
226		}
227	
228		adjustedInstall.Skills = remapSkillTargets(pkg.Install.Skills, agentSkillsDir, claudeSkillsDir)
229		adjusted.Install = adjustedInstall
230		return &adjusted
231	}
232	
233	// remapSkillTargets replaces relative .agents/skills and .claude/skills targets
234	// with the provided absolute directory paths.
235	func remapSkillTargets(mappings []registry.InstallMapping, agentSkillsDir, claudeSkillsDir string) []registry.InstallMapping {
236		result := make([]registry.InstallMapping, len(mappings))
237		for i, m := range mappings {
238			target := m.Target
239			t := filepath.ToSlash(target)
240			switch {
241			case strings.Contains(t, "agents/skills"):
242				target = strings.TrimRight(agentSkillsDir, "/") + "/"
243			case strings.Contains(t, "claude/skills"):
244				target = strings.TrimRight(claudeSkillsDir, "/") + "/"
245			}
246			result[i] = registry.InstallMapping{
247				Source: m.Source,
248				Target: target,
249			}
250		}
251		return result
252	}
