350	// installLocal installs a plugin from a local directory as a developer overlay.
351	// When global is true, the plugin root is linked into the machine-wide global
352	// plugin tree and skills are linked into the home-level harness directories.
353	// When global is false, the plugin root and skills land in the project tree
354	// (in-tree mode: <project>/.ddx/plugins/<name>; convention mode: XDG project path).
355	// Local installs intentionally do not update the recorded installed state and
356	// do not auto-commit so the recorded plugin pin remains whatever the project
357	// already declares.
358	func (f *CommandFactory) installLocal(name, localPath string, force bool, global bool, out io.Writer) error {
359		// Resolve to absolute path.
360		absPath, err := filepath.Abs(localPath)
361		if err != nil {
362			return fmt.Errorf("resolving path %s: %w", localPath, err)
363		}
364		if _, err := os.Stat(absPath); os.IsNotExist(err) {
365			return fmt.Errorf("local path does not exist: %s", absPath)
366		}
367	
368		// Load package.yaml when present so local installs honor the manifest
369		// contract. If package.yaml is absent, use the plugin manifest rather than
370		// assuming a repository layout from the package name.
371		reg := registry.BuiltinRegistry()
372		fallbackPkg, _ := reg.Find(name)
373	
374		pkg, manifestMissing, manifestIssues, manifestErr := registry.LoadPackageManifestWithFallback(absPath, fallbackPkg)
375		if manifestMissing {
376			pluginPkg, ok, pluginErr := loadLocalPluginManifestPackage(absPath, name)
377			if pluginErr != nil {
378				return pluginErr
379			}
380			if ok {
381				pkg = pluginPkg
382			} else {
383				pkg = &registry.Package{
384					Name:        name,
385					Version:     "local",
386					Description: "local plugin package",
387					Type:        registry.PackageTypePlugin,
388					Source:      absPath,
389				}
390			}
391		}
392		if manifestErr == nil {
393			if strings.TrimSpace(pkg.Name) != "" && pkg.Name != name {
394				return fmt.Errorf("local package name %q does not match package.yaml name %q", name, pkg.Name)
395			}
396		} else {
397			if os.IsNotExist(manifestErr) && manifestMissing {
398				// Already handled through package.yaml absence fallback above.
399			} else if len(manifestIssues) > 0 {
400				return fmt.Errorf("validating package manifest: %w", manifestErr)
401			} else {
402				return fmt.Errorf("loading package manifest: %w", manifestErr)
403			}
404		}
405	
406		if pkg == nil {
407			pkg = &registry.Package{
408				Name:        name,
409				Version:     "local",
410				Description: "local plugin package",
411				Type:        registry.PackageTypePlugin,
412				Source:      absPath,
413			}
414		}
415	
416		if pkg.Install.Root == nil {
417			pkg.Install.Root = &registry.InstallMapping{
418				Source: ".",
419				Target: fmt.Sprintf(".ddx/plugins/%s", pkg.Name),
420			}
421		}
422	
423		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
424			return fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
425		}
426	
427		projectRoot := f.WorkingDir
428		if projectRoot == "" {
429			projectRoot, _ = os.Getwd()
430		}
431		var oldFiles []string
432		if state, err := registry.LoadState(); err == nil {
433			if old := state.FindInstalled(pkg.Name); old != nil {
434				oldFiles = append([]string{}, old.Files...)
435				_, _ = markLocalInstallOverlay(projectRoot, pkg.Name, oldFiles)
436			}
437		}
438	
439		if issues := filterLocalInstallValidationIssues(absPath, registry.ValidatePackageStructure(absPath, pkg)); len(issues) > 0 {
440			return fmt.Errorf("validating package structure: %s", registry.JoinValidationIssues(issues))
441		}
442	
443		// Determine the actual plugin directory based on global vs project mode.
444		// Global: link into the machine-wide global tree.
445		// Project in-tree: link into <project>/.ddx/plugins/<name>.
446		// Project convention: link into the XDG convention root plugins/<name>.
447		// The FEAT-015 check above already validates that pkg.Install.Root.Target
448		// does not start with "~"; we now override the actual destination path.
449		var pluginDir string
450		if global {
451			pluginDir = filepath.Join(ddxroot.GlobalDir(), "plugins", name)
452		} else {
453			ddxRootDir := ddxroot.Path(context.Background(), f.WorkingDir)
454			pluginDir = filepath.Join(ddxRootDir, "plugins", name)
455		}
456	
457		if err := prepareSymlinkTarget(pluginDir, force); err != nil {
458			return err
459		}
460	
461		if err := os.MkdirAll(filepath.Dir(pluginDir), 0755); err != nil {
462			return fmt.Errorf("creating plugins dir: %w", err)
463		}
464	
465		if err := os.Symlink(absPath, pluginDir); err != nil {
466			return fmt.Errorf("linking plugin into %s: %w", pluginDir, err)
467		}
468	
469		fmt.Fprintf(out, "Linked %s -> %s\n", pluginDir, absPath)
470	
471		entry := registry.InstalledEntry{
472			Name:    pkg.Name,
473			Version: pkg.Version,
474			Type:    pkg.Type,
475			Source:  absPath,
476		}
477		// Record entry.Files as project-relative paths when the plugin lives inside
478		// the working directory (in-tree mode). Convention-root and global absolute
479		// paths are recorded as-is. This keeps removeStaleFilesFromInstall
480		// compatible with relative paths recorded by prior runs.
481		fileToRecord := pluginDir
482		if f.WorkingDir != "" {
483			if rel, relErr := filepath.Rel(f.WorkingDir, pluginDir); relErr == nil && !strings.HasPrefix(rel, "..") {
484				fileToRecord = rel
485			}
486		}
487		entry.Files = append(entry.Files, fileToRecord)
488	
489		// Install local skills as symlinks into each supported harness surface.
490		// For global installs, skills land in the home directory; for project
491		// installs, they land in the project directory.
492		if len(pkg.Install.Skills) > 0 {
493			var absProject string
494			if global {
495				absProject, _ = os.UserHomeDir()
496			} else {
497				absProject = f.WorkingDir
498				if absProject == "" {
499					absProject, _ = os.Getwd()
500				}
501			}
502			if !filepath.IsAbs(absProject) {
503				absProject, _ = filepath.Abs(absProject)
504			}
505			writtenSkills, err := installLocalSkillSymlinks(absPath, absProject, pkg.Install.Skills, force)
506			if err != nil {
507				return fmt.Errorf("installing skills: %w", err)
508			}
509			entry.Files = append(entry.Files, writtenSkills...)
510		}
511	
512		// Copy CLI script if defined (skip if target is a developer symlink).
513		if pkg.Install.Scripts != nil {
514			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
515			if li, lErr := os.Lstat(dst); lErr == nil && li.Mode()&os.ModeSymlink != 0 {
516				target, _ := os.Readlink(dst)
517				fmt.Fprintf(out, "notice: %s is a symlink тЖТ %s (developer mode, skipping copy)\n", dst, target)
518				entry.Files = append(entry.Files, dst)
519			} else {
520				copied, err := registry.CopyScriptFromRoot(pluginDir, pkg.Install.Scripts)
521				if err != nil {
522					fmt.Fprintf(out, "Warning: script copy error: %v\n", err)
523				} else {
524					entry.Files = append(entry.Files, copied)
525				}
526			}
527		}
528	
529		// Set execute bits on installed plugin files.
530		for _, rel := range pkg.Install.Executable {
531			p := filepath.Join(pluginDir, filepath.FromSlash(rel))
532			if info, err := os.Stat(p); err == nil && !info.IsDir() {
533				_ = os.Chmod(p, info.Mode()|0111)
534			}
535		}
536	
537		entry.InstalledAt = time.Now()
538	
539		removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
540		if removed > 0 {
541			fmt.Fprintf(out, "Removed %d stale file(s) from previous install\n", removed)
542		}
543	
544		// Git overlay hiding only applies to project-local installs (not global).
545		if !global {
546			if hidden, err := markLocalInstallOverlay(projectRoot, entry.Name, entry.Files); err != nil {
547				fmt.Fprintf(out, "Warning: local install is active but git overlay hiding failed: %v\n", err)
548			} else if hidden > 0 {
549				fmt.Fprintf(out, "Marked %d tracked local overlay file(s) skip-worktree\n", hidden)
550			}
551		}
552	
553		fmt.Fprintf(out, "Installed %s from local path %s тАФ %d file(s); recorded plugin pin unchanged\n", entry.Name, absPath, len(entry.Files))
554		return nil
555	}
556	
557	func markLocalInstallOverlay(projectRoot, pluginName string, files []string) (int, error) {
558		if projectRoot == "" {
559			return 0, nil
560		}
561	
562		ctx := context.Background()
563		topOut, err := internalgit.Command(ctx, projectRoot, "rev-parse", "--show-toplevel").Output()
564		if err != nil {
565			return 0, nil
566		}
567		repoRoot := strings.TrimSpace(string(topOut))
568		if repoRoot == "" {
569			return 0, nil
570		}
571	
572		paths := localOverlayPaths(pluginName, files)
573		if len(paths) == 0 {
574			return 0, nil
575		}
576		if err := addLocalOverlayIgnores(repoRoot, paths); err != nil {
577			return 0, err
578		}
579	
580		args := append([]string{"ls-files", "-z", "--"}, paths...)
581		trackedOut, err := internalgit.Command(ctx, repoRoot, args...).Output()
582		if err != nil {
583			return 0, err
584		}
585		var tracked []string
586		for _, p := range strings.Split(string(trackedOut), "\x00") {
587			if p != "" {
588				tracked = append(tracked, p)
589			}
590		}
591		for start := 0; start < len(tracked); start += 100 {
592			end := start + 100
593			if end > len(tracked) {
594				end = len(tracked)
595			}
596			args := append([]string{"update-index", "--skip-worktree", "--"}, tracked[start:end]...)
597			if err := internalgit.Command(ctx, repoRoot, args...).Run(); err != nil {
598				return 0, err
599			}
600		}
601		return len(tracked), nil
602	}
