639	func installLocalSkillSymlinks(pluginRoot, projectRoot string, mappings []registry.InstallMapping, force bool) ([]string, error) {
640		sourceRoots, err := localSkillSourceRoots(pluginRoot, mappings)
641		if err != nil {
642			return nil, err
643		}
644		if len(sourceRoots) == 0 {
645			return nil, nil
646		}
647	
648		var written []string
649		seenSkills := map[string]bool{}
650		for _, sourceRoot := range sourceRoots {
651			entries, err := os.ReadDir(sourceRoot)
652			if err != nil {
653				return nil, err
654			}
655			for _, entry := range entries {
656				if !entry.IsDir() && entry.Type()&os.ModeSymlink == 0 {
657					continue
658				}
659				name := entry.Name()
660				if seenSkills[name] {
661					continue
662				}
663				src := filepath.Join(sourceRoot, name)
664				if _, err := os.Stat(filepath.Join(src, "SKILL.md")); err != nil {
665					return nil, fmt.Errorf("%s: missing SKILL.md: %w", src, err)
666				}
667				for _, surface := range []string{".agents/skills", ".claude/skills"} {
668					dst := filepath.Join(projectRoot, filepath.FromSlash(surface), name)
669					if err := prepareSymlinkTarget(dst, force); err != nil {
670						return nil, err
671					}
672					if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
673						return nil, fmt.Errorf("creating skills dir: %w", err)
674					}
675					target, err := filepath.Rel(filepath.Dir(dst), src)
676					if err != nil {
677						target = src
678					}
679					if err := os.Symlink(target, dst); err != nil {
680						return nil, fmt.Errorf("linking skill %s -> %s: %w", dst, target, err)
681					}
682					written = append(written, filepath.Join(filepath.FromSlash(surface), name))
683				}
684				seenSkills[name] = true
685			}
686		}
687		return written, nil
688	}
