733			if os.IsNotExist(err) {
734				continue
735			}
736			if err != nil {
737				return nil, false, fmt.Errorf("loading plugin manifest %s: %w", path, err)
738			}
739			var manifest localPluginJSONManifest
740			if err := json.Unmarshal(data, &manifest); err != nil {
