757				Description: defaultString(strings.TrimSpace(manifest.Description), "local plugin package"),
758				Type:        registry.PackageTypePlugin,
759				Source:      defaultString(strings.TrimSpace(manifest.Repository), root),
760				Install: registry.PackageInstall{
761					Root: &registry.InstallMapping{
762						Source: ".",
763						Target: fmt.Sprintf(".ddx/plugins/%s", name),
764					},
765				},
766			}
