822	func addLocalOverlayIgnores(repoRoot string, paths []string) error {
823		excludePath := filepath.Join(repoRoot, ".git", "info", "exclude")
824		if err := os.MkdirAll(filepath.Dir(excludePath), 0o755); err != nil {
825			return err
826		}
827		existing, _ := os.ReadFile(excludePath)
828		text := string(existing)
829	
830		var additions []string
831		for _, p := range paths {
832			pattern := filepath.ToSlash(p)
833			candidates := []string{pattern}
834			if !strings.HasSuffix(pattern, "/") {
835				candidates = append(candidates, pattern+"/")
836			}
837			for _, candidate := range candidates {
838				if !strings.Contains(text, "\n"+candidate+"\n") && !strings.HasPrefix(text, candidate+"\n") {
839					additions = append(additions, candidate)
840				}
841			}
842		}
843		if len(additions) == 0 {
844			return nil
845		}
846	
847		var sb strings.Builder
848		if len(existing) > 0 && !strings.HasSuffix(text, "\n") {
849			sb.WriteString("\n")
850		}
851		if !strings.Contains(text, "# DDx local plugin overlays") {
852			sb.WriteString("\n# DDx local plugin overlays\n")
853		}
854		for _, pattern := range additions {
855			sb.WriteString(pattern)
856			sb.WriteString("\n")
857		}
858		return os.WriteFile(excludePath, append(existing, []byte(sb.String())...), 0o644)
859	}
