944			if err != nil {
945				abs = candidate
946			}
947			if !seen[abs] {
948				seen[abs] = true
949				aliases = append(aliases, abs)
950			}
951		}
952		add(path)
953		if resolved, err := filepath.EvalSymlinks(path); err == nil && resolved != "" {
