1081	func (f *CommandFactory) runVerify(cmd *cobra.Command, args []string) error {
1082		out := cmd.OutOrStdout()
1083	
1084		state, err := registry.LoadState()
1085		if err != nil {
1086			return fmt.Errorf("loading state: %w", err)
1087		}
1088	
1089		if len(state.Installed) == 0 {
1090			fmt.Fprintln(out, "No packages installed.")
1091			return nil
1092		}
1093	
1094		var totalIssues int
1095		for _, entry := range state.Installed {
1096			var issues []string
1097			for _, f := range entry.Files {
1098				expanded := registry.ExpandHome(f)
1099				info, err := os.Lstat(expanded)
1100				if os.IsNotExist(err) {
1101					issues = append(issues, fmt.Sprintf("  missing: %s", f))
1102					continue
1103				}
1104				if err != nil {
1105					issues = append(issues, fmt.Sprintf("  error: %s: %v", f, err))
1106					continue
1107				}
1108				// Check symlinks resolve.
1109				if info.Mode()&os.ModeSymlink != 0 {
1110					target, err := os.Readlink(expanded)
1111					if err != nil {
1112						issues = append(issues, fmt.Sprintf("  broken symlink: %s", f))
1113						continue
1114					}
1115					// Resolve relative symlinks against their parent directory.
1116					if !filepath.IsAbs(target) {
1117						target = filepath.Join(filepath.Dir(expanded), target)
1118					}
1119					if _, err := os.Stat(target); os.IsNotExist(err) {
1120						issues = append(issues, fmt.Sprintf("  broken symlink: %s -> %s", f, target))
1121					}
1122				}
1123			}
1124	
1125			if len(issues) == 0 {
1126				fmt.Fprintf(out, "%s %s: OK (%d files)\n", entry.Name, entry.Version, len(entry.Files))
1127			} else {
1128				fmt.Fprintf(out, "%s %s: %d issue(s)\n", entry.Name, entry.Version, len(issues))
1129				for _, issue := range issues {
1130					fmt.Fprintln(out, issue)
1131				}
1132				totalIssues += len(issues)
1133			}
1134		}
1135	
1136		if totalIssues > 0 {
1137			return fmt.Errorf("%d integrity issue(s) found тАФ run 'ddx install <name> --force' to repair", totalIssues)
1138		}
1139		return nil
1140	}
