1226		if len(outdated) == 0 {
1227			fmt.Fprintln(out, "All installed packages are up to date.")
1228			return nil
1229		}
1230	
1231		if asJSON {
1232			enc := json.NewEncoder(out)
1233			enc.SetIndent("", "  ")
1234			return enc.Encode(outdated)
1235		}
1236	
1237		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
1238		fmt.Fprintln(w, "NAME\tINSTALLED\tLATEST")
1239		for _, o := range outdated {
1240			fmt.Fprintf(w, "%s\t%s\t%s\n", o.Name, o.InstalledVersion, o.LatestVersion)
1241		}
1242		return w.Flush()
