120			_, _ = fmt.Fprint(cmd.OutOrStdout(), "тЬЕ DDx initialized successfully!\n")
121			_, _ = fmt.Fprintln(cmd.OutOrStdout())
122			_, _ = fmt.Fprint(cmd.OutOrStdout(), "Next steps:\n")
123			_, _ = fmt.Fprint(cmd.OutOrStdout(), "  ddx install helix   - Install HELIX workflow (optional)\n")
124			_, _ = fmt.Fprint(cmd.OutOrStdout(), "  ddx doctor          - Check installation health\n")
