412	func writeWorktreeRegistry(path string, registry worktreeRegistry) error {
413		data, err := json.MarshalIndent(registry, "", "  ")
414		if err != nil {
415			return err
416		}
417		data = append(data, '\n')
418		tmp := path + ".tmp"
