package cmd

import (
	"context"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestInstall_InTreeWritesProjectTreeAndLinks verifies bead AC1:
// with an in-tree <project>/.ddx/, `ddx install <name>` (no --global) writes
// to <project>/.ddx/plugins/<name>/ and creates project-tier links under
// <project>/.claude/skills/<name> and <project>/.agents/skills/<name>
// resolving into that plugins/ dir.
func TestInstall_InTreeWritesProjectTreeAndLinks(t *testing.T) {
	workDir := t.TempDir()
	homeDir := t.TempDir()
	t.Setenv("HOME", homeDir)

	// Force in-tree mode by pre-creating .ddx/.
	require.NoError(t, os.MkdirAll(filepath.Join(workDir, ddxroot.DirName), 0o755))

	localPlugin := t.TempDir()
	makeLocalPlugin(t, localPlugin, "myplugin")

	factory := NewCommandFactory(workDir)
	output, err := executeCommand(factory.NewRootCommand(), "install", "myplugin", "--local", localPlugin, "--force")
	require.NoError(t, err, output)

	// Plugin root must land in the in-tree location.
	projectPluginDir := filepath.Join(workDir, ddxroot.DirName, "plugins", "myplugin")
	pluginInfo, pluginStatErr := os.Lstat(projectPluginDir)
	require.NoError(t, pluginStatErr, "project plugin dir must exist at %s", projectPluginDir)
	assert.True(t, pluginInfo.Mode()&os.ModeSymlink != 0, "project plugin dir must be a symlink")

	// Project-tier skill links must be under the project directory and resolve
	// into the in-tree plugins/ tree (transitively through the plugin dir symlink).
	for _, surface := range []string{".agents/skills", ".claude/skills"} {
		skillLink := filepath.Join(workDir, surface, "myplugin-skill")
		skillInfo, skillErr := os.Lstat(skillLink)
		require.NoError(t, skillErr, "%s must exist for in-tree install", skillLink)
		assert.True(t, skillInfo.Mode()&os.ModeSymlink != 0 || skillInfo.IsDir(),
			"%s must be a symlink or dir for in-tree install", skillLink)

		realSkill, evalErr := filepath.EvalSymlinks(skillLink)
		require.NoError(t, evalErr, "%s must be resolvable", skillLink)
		assert.True(t, strings.HasPrefix(realSkill, localPlugin),
			"%s must resolve into local plugin source %s; got %s", skillLink, localPlugin, realSkill)
	}

	// Home directory must not be polluted.
	for _, surface := range []string{".agents/skills", ".claude/skills"} {
		_, noErr := os.Lstat(filepath.Join(homeDir, surface, "myplugin-skill"))
		assert.True(t, os.IsNotExist(noErr),
			"home %s must not be created for in-tree install", surface)
	}
}

// TestInstall_ConventionModeWritesXDGProjectTree verifies bead AC2:
// with no <project>/.ddx/, `ddx install <name>` (no --global) writes to
// ${XDG_DATA_HOME}/ddx/projects/<host>/<owner>/<repo>/plugins/<name>/
// and the project agent-tier links point into that XDG plugins/ path.
func TestInstall_ConventionModeWritesXDGProjectTree(t *testing.T) {
	workDir := t.TempDir()
	homeDir := t.TempDir()
	xdgDataHome := t.TempDir()
	t.Setenv("HOME", homeDir)
	t.Setenv("XDG_DATA_HOME", xdgDataHome)

	// Set up a git repo with a deterministic remote so host/owner/repo
	// derivation is predictable: github.com/testowner/testrepo.
	setupConventionGitRepo(t, workDir, "https://github.com/testowner/testrepo.git")

	// No .ddx/ in workDir тАФ convention mode.
	localPlugin := t.TempDir()
	makeLocalPlugin(t, localPlugin, "myplugin")

	factory := NewCommandFactory(workDir)
	output, err := executeCommand(factory.NewRootCommand(), "install", "myplugin", "--local", localPlugin, "--force")
	require.NoError(t, err, output)

	// Derive the convention root the same way ddxroot.Path does.
	conventionRoot := ddxroot.Path(context.Background(), workDir)

	// Convention root must be under XDG_DATA_HOME, not the in-tree .ddx/ path.
	assert.True(t, strings.HasPrefix(conventionRoot, xdgDataHome),
		"convention root must be under XDG_DATA_HOME; got %s", conventionRoot)
	assert.NotEqual(t, conventionRoot, filepath.Join(workDir, ddxroot.DirName),
		"convention root must not be the in-tree path when .ddx/ was not pre-created")

	// Plugin must land under the XDG convention root.
	conventionPluginDir := filepath.Join(conventionRoot, "plugins", "myplugin")
	pluginInfo, pluginStatErr := os.Lstat(conventionPluginDir)
	require.NoError(t, pluginStatErr, "convention plugin dir must exist at %s", conventionPluginDir)
	assert.True(t, pluginInfo.Mode()&os.ModeSymlink != 0,
		"convention plugin dir must be a symlink to local checkout")

	// Project-tier skill links must be in the project directory (not convention root or home).
	for _, surface := range []string{".agents/skills", ".claude/skills"} {
		skillLink := filepath.Join(workDir, surface, "myplugin-skill")
		skillInfo, skillErr := os.Lstat(skillLink)
		require.NoError(t, skillErr, "%s must exist for convention install", skillLink)
		assert.True(t, skillInfo.Mode()&os.ModeSymlink != 0 || skillInfo.IsDir(),
			"%s must be a symlink or dir for convention install", skillLink)

		// Skill must resolve into the local plugin source.
		realSkill, evalErr := filepath.EvalSymlinks(skillLink)
		require.NoError(t, evalErr, "%s must be resolvable", skillLink)
		assert.True(t, strings.HasPrefix(realSkill, localPlugin),
			"%s must resolve into local plugin source %s; got %s", skillLink, localPlugin, realSkill)
	}

	// Home directory must not be polluted.
	for _, surface := range []string{".agents/skills", ".claude/skills"} {
		_, noErr := os.Lstat(filepath.Join(homeDir, surface, "myplugin-skill"))
		assert.True(t, os.IsNotExist(noErr),
			"home %s must not be created for convention install", surface)
	}
}

// setupConventionGitRepo initialises a git repo in dir and registers remoteURL
// as the "origin" remote so that ddxroot.Path can derive a deterministic
// host/owner/repo identity for convention-mode path computation.
func setupConventionGitRepo(t *testing.T, dir, remoteURL string) {
	t.Helper()
	cleanEnv := gitpkg.CleanEnv()
	runGit := func(args ...string) {
		t.Helper()
		cmd := exec.Command("git", args...)
		cmd.Dir = dir
		cmd.Env = cleanEnv
		out, err := cmd.CombinedOutput()
		require.NoError(t, err, "git %v: %s", args, out)
	}
	runGit("init", "-q")
	runGit("config", "user.email", "test@example.com")
	runGit("config", "user.name", "Test User")
	runGit("remote", "add", "origin", remoteURL)
}
